using System;using System.Collections.Generic;class A{static string[][]G=new string[20][];static Dictionary<string,int>M=new();static int L,H;static long R(){int n=int.Parse(Console.ReadLine());var v=new string[n];for(int i=0;i<n;i++)v[i]=Console.ReadLine();long r=0;for(int i=0;i<n/H;i++){var k="";for(int j=0;j<H;j++){if(j>0)k+="\n";k+=v[i*H+j];}r=r*20+M[k];}return r;}static void Main(){var p=Console.ReadLine().Split(' ');L=int.Parse(p[0]);H=int.Parse(p[1]);for(int i=0;i<20;i++)G[i]=new string[H];for(int i=0;i<H;i++){var r=Console.ReadLine();for(int j=0;j<20;j++)G[j][i]=r.Substring(j*L,L);}for(int i=0;i<20;i++){var k="";for(int j=0;j<H;j++){if(j>0)k+="\n";k+=G[i][j];}M[k]=i;}long a=R(),b=R();var o=Console.ReadLine();long v2=o=="+"?a+b:o=="-"?a-b:o=="*"?a*b:a/b;var d=new List<int>();if(v2==0)d.Add(0);else while(v2>0){d.Insert(0,(int)(v2%20));v2/=20;}foreach(var x in d)for(int j=0;j<H;j++)Console.WriteLine(G[x][j]);}}